installation.script:
#!/bin/bash
set -euo pipefail

cd /mnt/server

echo "[FourthEye] Installing system dependencies"
if command -v apt-get >/dev/null 2>&1; then
  apt-get update
  apt-get install -y --no-install-recommends git ca-certificates
  rm -rf /var/lib/apt/lists/*
fi

if [ ! -d ".git" ]; then
  echo "[FourthEye] Cloning ${GIT_REPO} branch ${BRANCH}"
  tmp_dir="$(mktemp -d)"
  git clone --depth 1 --branch "${BRANCH}" "${GIT_REPO}" "${tmp_dir}"

  if [ -f "whitelist.json" ]; then
    cp whitelist.json /tmp/fourtheye-whitelist.json
  fi

  if [ -d "authentication_tokens" ]; then
    cp -a authentication_tokens /tmp/fourtheye-authentication-tokens
  fi

  find /mnt/server -mindepth 1 -maxdepth 1 -exec rm -rf {} +
  cp -a "${tmp_dir}/." /mnt/server/
  rm -rf "${tmp_dir}"

  if [ -f "/tmp/fourtheye-whitelist.json" ]; then
    cp /tmp/fourtheye-whitelist.json /mnt/server/whitelist.json
    rm -f /tmp/fourtheye-whitelist.json
  fi

  if [ -d "/tmp/fourtheye-authentication-tokens" ]; then
    cp -a /tmp/fourtheye-authentication-tokens /mnt/server/authentication_tokens
    rm -rf /tmp/fourtheye-authentication-tokens
  fi
else
  echo "[FourthEye] Existing git checkout detected; fetching ${BRANCH}"
  git fetch --depth 1 origin "${BRANCH}"
  git checkout "${BRANCH}" || git checkout -B "${BRANCH}" "origin/${BRANCH}"
  git pull --ff-only origin "${BRANCH}" || echo "[FourthEye] Pull skipped because local files differ. Existing install left in place."
fi

echo "[FourthEye] Installing Node dependencies"
npm install

if [ ! -f "whitelist.json" ]; then
  printf '{\n  "whitelist": []\n}\n' > whitelist.json
fi

cat > egg-config.mjs <<'EOF'
import { writeFileSync } from "node:fs";

const env = process.env;

function boolFromEnv(name, defaultValue = false) {
  const raw = env[name];

  if (raw === undefined || raw.trim() === "") {
    return defaultValue;
  }

  return ["1", "true", "yes", "on"].includes(raw.trim().toLowerCase());
}

function intFromEnv(name, defaultValue) {
  const raw = env[name];
  const parsed = Number.parseInt(raw ?? "", 10);

  return Number.isInteger(parsed) ? parsed : defaultValue;
}

function listFromEnv(name) {
  return (env[name] ?? "")
    .split(",")
    .map((item) => item.trim())
    .filter(Boolean);
}

function rgbFromEnv(name, defaultValue) {
  const values = (env[name] ?? "")
    .split(",")
    .map((item) => Number.parseInt(item.trim(), 10));

  if (values.length !== 3 || values.some((value) => !Number.isInteger(value) || value < 0 || value > 255)) {
    return defaultValue;
  }

  return values;
}

const defaultBedrockPort = intFromEnv("SERVER_PORT", 19132);

const config = {
  token: env.DISCORD_TOKEN ?? "",
  username: env.MC_USERNAME ?? "FourthEye",
  AuthType: boolFromEnv("OFFLINE_AUTH", false),
  isRealm: boolFromEnv("IS_REALM", false),
  realmInviteCode: env.REALM_INVITE_CODE ?? "",
  ip: env.BDS_HOST ?? env.SERVER_IP ?? "127.0.0.1",
  port: intFromEnv("BDS_PORT", defaultBedrockPort),
  guild: env.DISCORD_GUILD_ID ?? "",
  channel: env.DISCORD_CHANNEL_ID ?? "",
  systemCommandsChannel: env.DISCORD_SYSTEM_COMMANDS_CHANNEL_ID ?? "",
  cmdPrefix: env.COMMAND_PREFIX ?? "!",
  admins: listFromEnv("DISCORD_ADMIN_IDS"),
  useEmbed: boolFromEnv("USE_EMBED", true),
  setTitle: env.EMBED_TITLE ?? "FourthEye",
  setColor: rgbFromEnv("EMBED_COLOR", [0, 255, 0]),
  logoURL: env.LOGO_URL ?? "",
  useSystemPlayerJoinMessage: boolFromEnv("USE_SYSTEM_PLAYER_JOIN_MESSAGE", false),
  logSystemCommands: boolFromEnv("LOG_SYSTEM_COMMANDS", false),
  bedrockVersion: env.BEDROCK_VERSION ?? "",
  skipServerPing: boolFromEnv("SKIP_SERVER_PING", false),
  debug: boolFromEnv("DEBUG", false)
};

writeFileSync("config.js", `export default ${JSON.stringify(config, null, 2)};\n`);
EOF

echo "[FourthEye] Installation complete"
